+        kind: 'collect-evidence'
+      },
+      {
+        ...input.tasks[1],
+        id: 'task_002',
+        kind: 'collect-evidence'
+      },
+      {
+        ...input.tasks[2],
+        id: 'task_003',
+        kind: 'collect-evidence'
+      }
+    ];
+
+    const result = CompilationResultSchema.safeParse(input);
+    expect(result.success).toBe(false);
+  });
+});

